import java.util.*;

public class HandlerDecorators {

    interface RequestHandler {
        String handle(String path, Map<String, String> headers);
    }

    static class BaseHandler implements RequestHandler {
        public String handle(String path, Map<String, String> headers) {
            return "200 OK: " + path;
        }
    }

    static class LoggingDecorator implements RequestHandler {
        private final RequestHandler wrapped;
        private final List<String> log;

        LoggingDecorator(RequestHandler wrapped, List<String> log) {
            this.wrapped = wrapped;
            this.log = log;
        }

        public String handle(String path, Map<String, String> headers) {
            log.add("REQUEST: " + path);
            String result = wrapped.handle(path, headers);
            log.add("RESPONSE: " + result);
            return result;
        }
    }

    static class AuthDecorator implements RequestHandler {
        private final RequestHandler wrapped;

        AuthDecorator(RequestHandler wrapped) {
            this.wrapped = wrapped;
        }

        public String handle(String path, Map<String, String> headers) {
            // Check 'Authorization' header; return '401 Unauthorized' if absent
            // Otherwise, delegate to wrapped handler
            return null; // TODO
        }
    }

    public static void main(String[] args) {
        List<String> log = new ArrayList<>();

        RequestHandler chain = new LoggingDecorator(
            new AuthDecorator(
                new BaseHandler()
            ), log
        );

        String r1 = chain.handle("/api/data", Map.of("Authorization", "Bearer tok"));
        System.out.println(r1);
        String r2 = chain.handle("/api/data", Map.of());
        System.out.println(r2);
        System.out.println("Log entries: " + log.size());
    }
}

